<?php namespace App\Repositories\Library;use App\Repositories\BaseRepository;use App\Models\Library\Book;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class BookRepository extends BaseRepository{    public function __construct(Book $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByIsbn(string $isbn): ?Book    {        return $this->query()->where('isbn', $isbn)->first();    }    public function findByTitle(string $title): Collection    {        return $this->query()->where('title', 'like', "%{$title}%")->get();    }    public function findByAuthor(string $author): Collection    {        return $this->query()->where('author', 'like', "%{$author}%")->get();    }    public function findByCategory(int $categoryId): Collection    {        return $this->findByField('category_id', $categoryId);    }    public function findByPublisher(string $publisher): Collection    {        return $this->findByField('publisher', $publisher);    }    public function findByLanguage(string $language): Collection    {        return $this->findByField('language', $language);    }    public function getAvailableBooks(): Collection    {        return $this->query()->where('available_quantity', '>', 0)->get();    }    public function searchBooks(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('isbn', 'like', "%{$keyword}%")->orWhere('author', 'like', "%{$keyword}%")->orWhere('publisher', 'like', "%{$keyword}%")->orWhere('keywords', 'like', "%{$keyword}%")->get();    }    public function getRecentlyAdded(int $limit = 10): Collection    {        return $this->query()->orderBy('created_at', 'desc')->limit($limit)->get();    }    public function getByShelfLocation(string $location): Collection    {        return $this->findByField('shelf_location', $location);    }    public function updateQuantity(int $id, int $change): bool    {        $book = $this->getById($id);        $newQty = $book->available_quantity + $change;        return $this->update($id, [            'total_quantity' => max(0, $book->total_quantity + ($change > 0 ? $change : 0)),            'available_quantity' => max(0, $newQty),        ]);    }}